          <line x1="12" y1="8" x2="12" y2="3" />
          <line x1="20" y1="21" x2="20" y2="16" />
          <line x1="20" y1="12" x2="20" y2="3" />
          <line x1="1" y1="14" x2="7" y2="14" />
          <line x1="9" y1="8" x2="15" y2="8" />
          <line x1="17" y1="16" x2="23" y2="16" />
        </svg>
      </button>
    </Transition>

    \x3c!-- Trạng thái mở rộng: Bảng mục --\x3e
    <Transition name="panel">
      <div v-if="isPanelOpen" class="panel" :class="{ mobile: isMobile }" :style="panelStyle">
        \x3c!-- Thanh trên cùng --\x3e
        <div class="panel-top" :class="{ dragging: isPanelDragging }" @pointerdown="!isMobile && onPanelPointerDown($event)">
          <span class="panel-title">Chuyển mục</span>
          <span class="panel-preset">{{ currentPresetName }}</span>
          <button class="btn-icon" @click="isPanelOpen = false" @pointerdown.stop>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round">
              <line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" />
            </svg>
          </button>
        </div>

        \x3c!-- Danh sách mục --\x3e
        <div class="panel-body">
          \x3c!-- Chuyển mô hình --\x3e
          <div class="model-switch">
            <span class="model-label">Mô hình</span>
            <div class="model-toggle">
              <button
                class="model-btn"
                :class="{ active: currentModel === 'gemini' }"
                @click="switchModel('gemini')"
              >Gemini</button>
              <button
                class="model-btn"
                :class="{ active: currentModel === 'claude' }"
                @click="switchModel('claude')"
              >Claude</button>
            </div>
          </div>

          <div v-for="cat in categories" :key="cat.label" class="category">
            <div class="cat-label">{{ cat.label }}</div>
            <div class="cat-items">
              <button
                v-for="item in cat.items"
                :key="item.name"
                class="item"
                :class="{ on: item.enabled }"
                @click="togglePrompt(item.name)"
              >
                <span class="dot" />
                <span class="item-name">{{ item.displayName }}</span>
              </button>
            </div>
          </div>
          <div v-if="categories.length === 0" class="empty">Không phát hiện mục nào có thể điều khiển</div>
        </div>
      </div>
    </Transition>
  </div>
</template>

<script setup lang="ts">
// ─── Hằng số ───
const STORAGE_KEY = 'preset-switcher-fab-pos';
const EDGE_GAP = 12;
const FAB_SIZE = 44;
const DRAG_THRESHOLD = 3;

// ─── Cửa sổ host ───
const hostWindow = window.parent;
const windowWidth = ref(hostWindow.innerWidth);
const windowHeight = ref(hostWindow.innerHeight);
const isMobile = computed(() => windowWidth.value <= 500);

// ─── Định nghĩa phân loại ───
interface Category {
  label: string;
  items: { name: string; displayName: string; enabled: boolean }[];
}

// Ánh xạ tên mục sang phân loại
function classifyPrompt(name: string): string {
  // Liên quan nhân vật
  if (/Nền tảng nhân vật|Tổng quan nhân vật|Bảng pha màu tính cách|Tam diện tính|Tái diễn giải|Bảng pha màu NSFW|Thiết kế NPC|Tủ đồ/.test(name)) return 'Nhân vật';
  // Thế giới & Cảnh
  if (/Thế giới quan|Card quay tay|Lời mở màn/.test(name)) return 'Thế giới & Cảnh';
  // MVU
  if (/MVU/.test(name)) return 'MVU';
  // EJS
  if (/EJS/.test(name)) return 'EJS';
  // Công cụ sáng tác
  if (/Trợ lý sáng tác tự do|Làm đẹp frontend|Đánh giá worldbook/.test(name)) return 'Công cụ sáng tác';
  // Giá trị dự phòng
  return 'Khác';
}

// Loại bỏ phần này trong tên mục emoji Tiền tố，Chỉ hiển thị tên cốt lõi
function displayName(name: string): string {
  return name.replace(/^[^\p{L}\p{N}]+/u, '').trim() || name;
}

// ─── Trạng thái bảng ───
const isPanelOpen = ref(false);

// ─── Chuyển mô hình ───
type ModelType = 'gemini' | 'claude';
const SNAKE_PROMPT_NAME = '🐍 Thu Thanh Tử nuốt mất chuỗi suy nghĩ gốc';
const currentModel = ref<ModelType>('gemini');

function detectCurrentModel(preset: Preset): ModelType {
  return preset.settings.max_context >= 2000000 ? 'gemini' : 'claude';
}

async function switchModel(model: ModelType) {
  if (model === currentModel.value) return;
  currentModel.value = model;

  try {
    await updatePresetWith('in_use', preset => {
      if (model === 'gemini') {
        preset.settings.max_context = 2000000;
        // Bật「Thu Thanh Tử nuốt mất chuỗi suy nghĩ gốc」
        const p = preset.prompts.find(
          p => (isPresetNormalPrompt(p) || isPresetSystemPrompt(p)) && p.name === SNAKE_PROMPT_NAME,
        );
        if (p) p.enabled = true;
      } else {
        preset.settings.max_context = 200000;
        // Tắt「Thu Thanh Tử nuốt mất chuỗi suy nghĩ gốc」
        const p = preset.prompts.find(
          p => (isPresetNormalPrompt(p) || isPresetSystemPrompt(p)) && p.name === SNAKE_PROMPT_NAME,
        );
        if (p) p.enabled = false;
      }
      return preset;
    });
    refreshPresetData();
  } catch (e) {
    // Quay lui
    currentModel.value = model === 'gemini' ? 'claude' : 'gemini';
    console.error('[script chuyển đổi] Chuyển mô hình thất bại:', e);
  }
}

// ─── Dữ liệu preset ───
const currentPresetName = ref('');
const promptEnabledMap = ref<Record<string, boolean>>({});
const sectionPromptNames = ref<string[]>([]);

// ─── Dấu mốc khoảng ───
function extractSectionPrompts(prompts: PresetPrompt[]): string[] {
  const result: string[] = [];
  let inSection = false;
  for (const p of prompts) {
    if (!isPresetNormalPrompt(p) && !isPresetSystemPrompt(p)) continue;
    const n = p.name;
    if (n === '【Mục thông thường】' || n === '【MVUMục】') { inSection = true; continue; }
    if (n === '【/Mục thông thường】' || n === '【/MVUMục】') { inSection = false; continue; }
    if (inSection) result.push(n);
  }
  return result;
}

function refreshPresetData() {
  try {
    currentPresetName.value = getLoadedPresetName();
    const preset = getPreset('in_use');

    // Kiểm tra mô hình hiện tại
    currentModel.value = detectCurrentModel(preset);

    const names = extractSectionPrompts(preset.prompts);
    sectionPromptNames.value = names;
    const map: Record<string, boolean> = {};
    for (const p of preset.prompts) {
      if ((isPresetNormalPrompt(p) || isPresetSystemPrompt(p)) && names.includes(p.name)) {
        map[p.name] = p.enabled;
      }
    }
    promptEnabledMap.value = map;
  } catch (e) {
    console.warn('[script chuyển đổi] Làm mới dữ liệu preset thất bại:', e);
  }
}

// Tính danh sách phân loại
const categories = computed<Category[]>(() => {
  const catMap = new Map<string, Category>();
  // Theo thứ tự do phân loại định nghĩa
  const order = ['Nhân vật', 'Thế giới & Cảnh', 'Công cụ sáng tác', 'MVU', 'EJS', 'Khác'];

  for (const name of sectionPromptNames.value) {
    const cat = classifyPrompt(name);
    if (!catMap.has(cat)) {
      catMap.set(cat, { label: cat, items: [] });
    }
    catMap.get(cat)!.items.push({
      name,
      displayName: displayName(name),
      enabled: promptEnabledMap.value[name] ?? false,
    });
  }

  return order.filter(k => catMap.has(k)).map(k => catMap.get(k)!);
});

// Làm mới ban đầu
refreshPresetData();
const refreshTimer = setInterval(refreshPresetData, 3000);
onUnmounted(() => clearInterval(refreshTimer));

// ─── Chuyển từngMục ───
async function togglePrompt(name: string) {
  const current = promptEnabledMap.value[name] ?? false;
  // Cập nhật lạc quan
  promptEnabledMap.value[name] = !current;
  try {
    await updatePresetWith('in_use', preset => {
      const p = preset.prompts.find(
        p => (isPresetNormalPrompt(p) || isPresetSystemPrompt(p)) && p.name === name,
      );
      if (p) p.enabled = !current;
      return preset;
    });
  } catch (e) {
    // Quay lui
    promptEnabledMap.value[name] = current;
    console.error('[script chuyển đổi] Chuyển đổi thất bại:', e);
  }
}

// ─── FAB Vị trí ───
function defaultFabPos() {
  return { x: hostWindow.innerWidth - FAB_SIZE - 16, y: hostWindow.innerHeight * 0.4 };
}

function readFabPos(): { x: number; y: number } {
  try {
    const raw = hostWindow.localStorage.getItem(STORAGE_KEY);
    if (raw) return JSON.parse(raw);
  } catch { /* ignore */ }
  return defaultFabPos();
}

function saveFabPos(pos: { x: number; y: number }) {
  try { hostWindow.localStorage.setItem(STORAGE_KEY, JSON.stringify(pos)); } catch { /* ignore */ }
}

function clampPos(x: number, y: number) {
  const vw = hostWindow.innerWidth;
  const vh = hostWindow.innerHeight;
  return {
    x: _.clamp(x, EDGE_GAP, Math.max(EDGE_GAP, vw - FAB_SIZE - EDGE_GAP)),
    y: _.clamp(y, EDGE_GAP, Math.max(EDGE_GAP, vh - FAB_SIZE - EDGE_GAP)),
  };
}

const fabPos = reactive(clampPos(readFabPos().x, readFabPos().y));
const fabStyle = computed(() => ({ left: `${fabPos.x}px`, top: `${fabPos.y}px` }));

function setFabPos(x: number, y: number) {
  const c = clampPos(x, y);
  fabPos.x = c.x;
  fabPos.y = c.y;
  saveFabPos(c);
}

// ─── FAB Kéo ───
const isDragging = ref(false);
const fabRef = ref<HTMLButtonElement | null>(null);
let dragStart = { x: 0, y: 0 };
let dragBase = { x: 0, y: 0 };
let hasMoved = false;

function onFabPointerDown(e: PointerEvent) {
  if (e.button !== 0) return;
  e.preventDefault();
  isDragging.value = false;
  hasMoved = false;
  dragStart = { x: e.clientX, y: e.clientY };
  dragBase = { x: fabPos.x, y: fabPos.y };
  hostWindow.addEventListener('pointermove', onFabPointerMove);
  hostWindow.addEventListener('pointerup', onFabPointerUp);
}

function onFabPointerMove(e: PointerEvent) {
  const dx = e.clientX - dragStart.x;
  const dy = e.clientY - dragStart.y;
  if (!hasMoved && Math.abs(dx) <= DRAG_THRESHOLD && Math.abs(dy) <= DRAG_THRESHOLD) return;
  hasMoved = true;
  isDragging.value = true;
  setFabPos(dragBase.x + dx, dragBase.y + dy);
}

function onFabPointerUp() {
  hostWindow.removeEventListener('pointermove', onFabPointerMove);
  hostWindow.removeEventListener('pointerup', onFabPointerUp);
  isDragging.value = false;
  if (!hasMoved) {
    isPanelOpen.value = true;
    refreshPresetData();
  }
}

// ─── Kéo bảng ───
const isPanelDragging = ref(false);
const panelOffset = ref<{ x: number; y: number } | null>(null);
let panelDragStart = { x: 0, y: 0 };
let panelDragBase = { x: 0, y: 0 };
let panelHasMoved = false;

const PANEL_W = 320;
const PANEL_H = 460;

function calcPanelInitPos() {
  if (isMobile.value) return { x: 0, y: 0 };
  const vw = hostWindow.innerWidth;
  const vh = hostWindow.innerHeight;
  let left = fabPos.x > vw * 0.5 ? fabPos.x + FAB_SIZE - PANEL_W : fabPos.x;
  left = _.clamp(left, EDGE_GAP, Math.max(EDGE_GAP, vw - PANEL_W - EDGE_GAP));
  const above = fabPos.y - PANEL_H - 10;
  const below = fabPos.y + FAB_SIZE + 10;
  let top = above >= EDGE_GAP ? above : below + PANEL_H <= vh - EDGE_GAP ? below : _.clamp(above, EDGE_GAP, Math.max(EDGE_GAP, vh - PANEL_H - EDGE_GAP));
  return { x: left, y: top };
}

const panelStyle = computed(() => {
  if (isMobile.value) return { left: '0', top: '0', width: '100vw', height: '100vh' };
  const pos = panelOffset.value ?? calcPanelInitPos();
  return { left: `${pos.x}px`, top: `${pos.y}px`, width: `${PANEL_W}px`, height: `${PANEL_H}px` };
});

watch(isPanelOpen, open => { if (open) panelOffset.value = null; });

function onPanelPointerDown(e: PointerEvent) {
  if (e.button !== 0 || isMobile.value) return;
  e.preventDefault();
  isPanelDragging.value = false;
  panelHasMoved = false;
  panelDragStart = { x: e.clientX, y: e.clientY };
  const cur = panelOffset.value ?? calcPanelInitPos();
  panelDragBase = { x: cur.x, y: cur.y };
  hostWindow.addEventListener('pointermove', onPanelPointerMove);
  hostWindow.addEventListener('pointerup', onPanelPointerUp);
}

function onPanelPointerMove(e: PointerEvent) {
  const dx = e.clientX - panelDragStart.x;
  const dy = e.clientY - panelDragStart.y;
  if (!panelHasMoved && Math.abs(dx) <= DRAG_THRESHOLD && Math.abs(dy) <= DRAG_THRESHOLD) return;
  panelHasMoved = true;
  isPanelDragging.value = true;
  const vw = hostWindow.innerWidth;
  const vh = hostWindow.innerHeight;
  panelOffset.value = {
    x: _.clamp(panelDragBase.x + dx, EDGE_GAP, Math.max(EDGE_GAP, vw - PANEL_W - EDGE_GAP)),
    y: _.clamp(panelDragBase.y + dy, EDGE_GAP, Math.max(EDGE_GAP, vh - PANEL_H - EDGE_GAP)),
  };
}

function onPanelPointerUp() {
  hostWindow.removeEventListener('pointermove', onPanelPointerMove);
  hostWindow.removeEventListener('pointerup', onPanelPointerUp);
  isPanelDragging.value = false;
}

// ─── resize ───
const onResize = () => {
  windowWidth.value = hostWindow.innerWidth;
  windowHeight.value = hostWindow.innerHeight;
  setFabPos(fabPos.x, fabPos.y);
};
onMounted(() => hostWindow.addEventListener('resize', onResize));
onUnmounted(() => hostWindow.removeEventListener('resize', onResize));
</script>

